update content 
set warning_status = #{warningStatus},
    update_time = #{updateTime}
where id = #{id}

mapper.select:
select date(create_time) as date, risk_level, count(*) as count from content where risk_level > 0
and create_time >= #{startTime}
and create_time <= #{endTime}
group by date(create_time), risk_level order by date(create_time), risk_level

select c.*, cat.topic_name from content c left join topic cat on c.topic_id = cat.id 
where c.risk_level >= #{minRiskLevel}
order by c.risk_score desc, c.create_time desc
limit #{limit}


select t.date, count(distinct t.anonymous_id) as activeUsers,
       sum(case when t.behavior_type = 0 then 1 else 0 end) as posts
from (
    select date(create_time) as date, anonymous_id, 0 as behavior_type from content 
    where 1=1


         and date(create_time) >= #{startDate} 


         and date(create_time) <= #{endDate} 


         and create_time >= date_sub(curdate(), interval 30 day) 


    union all
    select date(create_time) as date, anonymous_id, behavior_type as behavior_type from user_behavior
    where 1=1


         and date(create_time) >= #{startDate} 


         and date(create_time) <= #{endDate} 


         and create_time >= date_sub(curdate(), interval 30 day) 


) t
group by t.date order by t.date desc

